{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires deriving a general scaling exponent (De Giorgi exponent) for a class of dissipative PDEs and then verifying its consistency across specific physical models. The decomposition breaks this into formula derivation, scaling analysis, and model-specific verification.",
  "helpers": [
    {
      "label": "derive_general_exponent",
      "instructions": "Derive the general scaling exponent $\alpha$ (or the critical regularity index) for a dissipative PDE of the form $\partial_t u + (u \cdot \nabla) u + (-\Delta)^s u = 0$ in $n$ dimensions. Use dimensional analysis or scaling symmetry $u_\lambda(x, t) = \lambda^\alpha u(\lambda x, \lambda^{2s} t)$ to find the relationship between $n$, $s$, and the critical exponent."
    },
    {
      "label": "verify_navier_stokes_cases",
      "instructions": "Apply the derived formula to the 3D Navier-Stokes ($n=3, s=1$) and 2D Navier-Stokes ($n=2, s=1$) equations. Confirm if the formula yields the correct critical space/exponent (e.g., $L^3$ in 3D or $L^2$ in 2D)."
    },
    {
      "label": "verify_burgers_and_sqg",
      "instructions": "Apply the formula to the 1D Burgers equation ($n=1, s=1$) and the Surface Quasi-Geostrophic (SQG) equation (where $s$ varies, typically $s=1/2$ or $s \in (0,1)$). Check for consistency with known critical regularity thresholds."
    },
    {
      "label": "verify_mhd_and_fractional_ns",
      "instructions": "Apply the formula to Magnetohydrodynamics (MHD) and fractional Navier-Stokes equations. Ensure the formula accounts for the coupling in MHD and the arbitrary diffusion order $s$ in fractional NS."
    }
  ],
  "synthesis_brief": "The parent node will collect the general formula from 'derive_general_exponent' and the verification results from the other three helpers. It will then synthesize the final answer by stating the universal formula (likely expressed in terms of $n$ and $s$) and providing a summary table or list confirming that the formula correctly predicts the critical exponents for all 6 specified PDEs."
}
```

